const prompt = `Ты строгий бизнес-ассистент. Твоя задача — извлечь из транскрипта созвона или чата ВСЕ обещания, задачи и дедлайны.

ПРАВИЛА:
1. Ищи фразы вроде "я сделаю это завтра", "отправлю до пятницы", "нужно проверить остатки", "поставь задачу на...".
2. Если задач и дедлайнов НЕТ, верни строго пустой JSON массив: []
3. Если задачи есть, верни JSON массив объектов следующего формата (и больше никакого текста!):
[
  {
    "task": "Краткая суть задачи (например: Отправить коммерческое предложение)",
    "assignee": "Кто должен сделать (например: Евгений, или Клиент, или Неизвестно)",
    "deadline": "Упомянутый срок (например: 15 марта, завтра, до конца недели, без срока)",
    "context": "Краткий контекст из-за чего возникла задача (1 предложение)"
  }
]`;

return [{ json: { systemPrompt: prompt } }];

const result = $json;
let tasks = [];

try {
  // Support both Anthropic and OpenAI response formats
  let content = '';
  if (result.content && Array.isArray(result.content)) {
    content = result.content.filter(b => b.type === 'text').map(b => b.text).join('\n').trim();
  } else if (result.choices && result.choices[0]) {
    content = (result.choices[0].message.content || '').trim();
  }
  tasks = JSON.parse(content);
  if (!Array.isArray(tasks)) tasks = [tasks]; // Fallback if AI returns single object
} catch (e) {
  tasks = [];
}

// Get original data from previous node (because N8N HTTP request replaces $json)
const original = $('Has Data?').first().json;

return [{
  json: {
    ...original,
    tasks: tasks,
    hasTasks: tasks.length > 0
  }
}];
